package membership

import (
	"math/bits"
	"sync"
	"time"
)

// ScaledConfig derives SWIM settings from an estimated cluster size.
//
// Scaling uses ceil(log2(clusterSize)) levels. A one-node cluster has level 0,
// two nodes has level 1, three or four nodes have level 2, and so on. This
// keeps growth deterministic and monotonic while adding only logarithmic cost.
type ScaledConfig struct {
	// Base is the configuration used for zero or one observed node.
	Base SWIMConfig

	// ProtocolPeriodStep is added to Base.ProbeInterval for each log2 level.
	ProtocolPeriodStep time.Duration

	// ProbeTimeoutStep is added to Base.ProbeTimeout for each log2 level.
	ProbeTimeoutStep time.Duration

	// SuspicionTimeoutStep is added to Base.SuspicionTimeout for each log2 level.
	SuspicionTimeoutStep time.Duration

	// IndirectChecksStep is added every IndirectChecksStepEvery log2 levels.
	IndirectChecksStep int

	// IndirectChecksStepEvery controls how often indirect checks increase.
	// Values less than one are treated as one.
	IndirectChecksStepEvery int

	// MaxIndirectChecks caps scaled indirect fanout. A value less than one means
	// no cap is applied.
	MaxIndirectChecks int
}

// DefaultScaling returns stable log2-based defaults for SWIM scaling.
func DefaultScaling() ScaledConfig {
	return ScaledConfig{
		Base:                    DefaultSWIMConfig(),
		ProtocolPeriodStep:      250 * time.Millisecond,
		ProbeTimeoutStep:        50 * time.Millisecond,
		SuspicionTimeoutStep:    time.Second,
		IndirectChecksStep:      1,
		IndirectChecksStepEvery: 2,
		MaxIndirectChecks:       10,
	}
}

// ConfigForClusterSize returns a SWIMConfig scaled for clusterSize.
func (c ScaledConfig) ConfigForClusterSize(clusterSize int) SWIMConfig {
	return SWIMConfig{
		ProbeInterval:    c.ProtocolPeriod(clusterSize),
		ProbeTimeout:     c.ProbeTimeout(clusterSize),
		IndirectChecks:   c.IndirectChecks(clusterSize),
		SuspicionTimeout: c.SuspicionTimeout(clusterSize),
	}
}

// ProtocolPeriod returns the scaled SWIM protocol period.
func (c ScaledConfig) ProtocolPeriod(clusterSize int) time.Duration {
	return scaleDuration(c.Base.ProbeInterval, c.ProtocolPeriodStep, log2Level(clusterSize))
}

// ProbeTimeout returns the scaled direct probe timeout.
func (c ScaledConfig) ProbeTimeout(clusterSize int) time.Duration {
	return scaleDuration(c.Base.ProbeTimeout, c.ProbeTimeoutStep, log2Level(clusterSize))
}

// SuspicionTimeout returns the scaled suspect-to-dead timeout.
func (c ScaledConfig) SuspicionTimeout(clusterSize int) time.Duration {
	return scaleDuration(c.Base.SuspicionTimeout, c.SuspicionTimeoutStep, log2Level(clusterSize))
}

// IndirectChecks returns the scaled indirect probe fanout.
func (c ScaledConfig) IndirectChecks(clusterSize int) int {
	level := log2Level(clusterSize)
	every := c.IndirectChecksStepEvery
	if every < 1 {
		every = 1
	}
	step := c.IndirectChecksStep
	if step < 0 {
		step = 0
	}

	checks := scaleInt(c.Base.IndirectChecks, step, level/every)
	if c.MaxIndirectChecks > 0 && checks > c.MaxIndirectChecks {
		return c.MaxIndirectChecks
	}
	if checks < 0 {
		return 0
	}
	return checks
}

// ClusterSizeEstimator tracks unique observed node IDs for scaling decisions.
type ClusterSizeEstimator struct {
	mu    sync.RWMutex
	nodes map[string]struct{}
}

// NewClusterSizeEstimator returns an estimator seeded with any provided node IDs.
func NewClusterSizeEstimator(nodeIDs ...string) *ClusterSizeEstimator {
	e := &ClusterSizeEstimator{
		nodes: make(map[string]struct{}, len(nodeIDs)),
	}
	e.ObserveMany(nodeIDs...)
	return e
}

// Observe records a node ID. It reports whether the estimate increased.
func (e *ClusterSizeEstimator) Observe(nodeID string) bool {
	e.mu.Lock()
	defer e.mu.Unlock()
	if e.nodes == nil {
		e.nodes = make(map[string]struct{})
	}
	if _, ok := e.nodes[nodeID]; ok {
		return false
	}
	e.nodes[nodeID] = struct{}{}
	return true
}

// ObserveMany records node IDs and returns how many were new.
func (e *ClusterSizeEstimator) ObserveMany(nodeIDs ...string) int {
	added := 0
	for _, nodeID := range nodeIDs {
		if e.Observe(nodeID) {
			added++
		}
	}
	return added
}

// Estimate returns the current cluster size estimate.
func (e *ClusterSizeEstimator) Estimate() int {
	e.mu.RLock()
	defer e.mu.RUnlock()
	return len(e.nodes)
}

// Reset clears all observations.
func (e *ClusterSizeEstimator) Reset() {
	e.mu.Lock()
	defer e.mu.Unlock()
	e.nodes = make(map[string]struct{})
}

func log2Level(clusterSize int) int {
	if clusterSize <= 1 {
		return 0
	}
	return bits.Len(uint(clusterSize - 1))
}

func scaleDuration(base, step time.Duration, level int) time.Duration {
	if step <= 0 || level <= 0 {
		return base
	}
	if base >= maxDuration {
		return maxDuration
	}
	if int64(level) > int64(maxDuration)/int64(step) {
		return maxDuration
	}
	increment := time.Duration(level) * step
	if base > maxDuration-increment {
		return maxDuration
	}
	return base + increment
}

func scaleInt(base, step, level int) int {
	if step <= 0 || level <= 0 {
		return base
	}
	maxInt := int(^uint(0) >> 1)
	if base >= maxInt {
		return maxInt
	}
	if level > maxInt/step {
		return maxInt
	}
	increment := step * level
	if base > maxInt-increment {
		return maxInt
	}
	return base + increment
}

const maxDuration = time.Duration(1<<63 - 1)

